import React, { useState } from 'react';

const language = [
    {
        lang: 'C++.png',
        proficiency: 3
    }
];
const LanguageList = () => {
    const languageList = language.map((item)=>{
        return <img src={require(`../resources/${item.lang}`)} alt="CPlus"/>
    });
    const proficiencyLevel = [];
    for(var i = 0; i < language.length;i++)
    {
        for(var n = 0; n < language[i].proficiency;n++)
        {
            proficiencyLevel.push(<div className="cell"><i className="check icon"></i></div>);
            if(language[i].proficiency < 5 && (n == language[i].proficiency-1))
            {
                proficiencyLevel.push(<div className="cell"><i></i></div>);
            }
        }
    }
    return (<div className="grid assessmentContent">
        <div className="cell">
            <div className="ui small image" style={{borderRadius:"50%",padding: "0em", maxHeight:"2rem",maxWidth:"2rem",zIndex:"5"}}>
                { languageList }
            </div>
        </div>
        { proficiencyLevel }
    </div>);
};

export default LanguageList;
